### Nano Banana 正式提交

def get_lan_ip() -> str:
    try:
        if sys.platform == "win32":
            out = subprocess.check_output(["ipconfig"], text=True, stderr=subprocess.DEVNULL, encoding="gbk", errors="replace")
            for line in out.splitlines():
                line = line.strip()
                if "IPv4" in line and "127.0.0.1" not in line:
                    ip = line.rsplit(":", 1)[-1].strip()
                    if ip.startswith("192.168.") or ip.startswith("10.") or ip.startswith("172."):
                        return ip
        else:
            out = subprocess.check_output(["ifconfig"], text=True, stderr=subprocess.DEVNULL)
            for line in out.splitlines():
                if "inet " in line and "127.0.0.1" not in line:
                    ip = line.strip().split()[1]
                    if ip.startswith("192.168.") or ip.startswith("10.") or ip.startswith("172."):
                        return ip
    except Exception:
        pass
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.connect(("8.8.8.8", 80))
        ip = s.getsockname()[0]
        s.close()
        return ip
    except Exception:
        return "127.0.0.1"

def _find_openssl() -> str | None:
    """Find openssl binary. Returns path or None."""
    import shutil
    which = shutil.which("openssl")
    if which:
        return which
    # Windows: check common Git/OpenSSL install paths
    if sys.platform == "win32":
        candidates = [
            r"C:\Program Files\Git\usr\bin\openssl.exe",
            r"C:\Program Files\OpenSSL\bin\openssl.exe",
            r"C:\Program Files (x86)\Git\usr\bin\openssl.exe",
        ]
        for p in candidates:
            if Path(p).exists():
                return p
    return None

class AppManager:
    def __init__(self):
        self.processes: dict[str, subprocess.Popen] = {}
        self.log_handles: dict[str, Any] = {}
        self.status: dict[str, dict[str, Any]] = {}
        self._stop_event = threading.Event()

def start_all(self):
    for name, config in APPS.items():
        self.start_app(name, config)
    threading.Thread(target=self._health_loop, daemon=True).start()

def start_app(self, name: str, config: dict):
    app_dir = config["dir"]
    if not (app_dir / "app.py").exists():
        self.status[name] = {"status": "missing", "error": "app.py not found"}
        return
    env = os.environ.copy()
    env["PORT"] = str(config["port"])
    env["HOST"] = "127.0.0.1"
    env["CORS"] = "1"
    # 测试环境：每个子应用的数据重定向到各自的 test-data/ 目录
    if "DATA_DIR" in os.environ:
        env["DATA_DIR"] = str(app_dir / "test-data")
    old_log = self.log_handles.pop(name, None)
    if old_log:
        try:
            old_log.close()
        except Exception:
            pass
    log_dir = STATE_DIR / "logs"
    log_dir.mkdir(parents=True, exist_ok=True)
    log_file = (log_dir / f"{name}.log").open("ab", buffering=0)
    try:
        proc = subprocess.Popen(
            [sys.executable, "app.py"],
            cwd=str(app_dir),
            env=env,
            stdout=log_file,
            stderr=subprocess.STDOUT,
            **_POPEN_EXTRA,
        )
    except Exception as exc:
        log_file.close()
        self.status[name] = {"status": "crashed", "error": str(exc), "port": config["port"]}
        return
    self.log_handles[name] = log_file
    self.processes[name] = proc
    self.status[name] = {"status": "starting", "port": config["port"], "pid": proc.pid}

def _health_loop(self):
    while not self._stop_event.is_set():
        time.sleep(10)
        for name, config in APPS.items():
            proc = self.processes.get(name)
            if proc and proc.poll() is not None:
                self.status[name] = {"status": "crashed", "exit_code": proc.returncode}
                self.start_app(name, config)
                continue
            try:
                conn = http.client.HTTPConnection("127.0.0.1", config["port"], timeout=5)
                conn.request("GET", "/api/v1/meta")
                resp = conn.getresponse()
                if resp.status == 200:
                    meta = json.loads(resp.read())
                    self.status[name] = {"status": "ready", "port": config["port"], "meta": meta}
                else:
                    self.status[name] = {"status": "unhealthy", "port": config["port"]}
                conn.close()
            except Exception:
                if proc and proc.poll() is None:
                    self.status[name] = {"status": "starting", "port": config["port"]}
                else:
                    self.status[name] = {"status": "down", "port": config["port"]}

def shutdown(self):
    self._stop_event.set()
    for name, proc in self.processes.items():
        if proc.poll() is None:
            proc.terminate()
    for name, proc in self.processes.items():
        try:
            proc.wait(timeout=5)
        except subprocess.TimeoutExpired:
            proc.kill()
    for handle in self.log_handles.values():
        try:
            handle.close()
        except Exception:
            pass
    self.log_handles.clear()

class UsageTracker:
    def __init__(self):
        self._lock = threading.Lock()
        self._data = self._load()
        self._pending_jobs: list[dict] = []
        threading.Thread(target=self._job_poll_loop, daemon=True).start()

def _load(self) -> dict[str, Any]:
    if USAGE_PATH.exists():
        try:
            return json.loads(USAGE_PATH.read_text("utf-8"))
        except Exception:
            pass
    return {"records": [], "daily": {}}

def _save(self):
    STATE_DIR.mkdir(parents=True, exist_ok=True)
    USAGE_PATH.write_text(json.dumps(self._data, ensure_ascii=False, indent=2), "utf-8")

def register_job(self, app: str, job_id: str, client_ip: str):
    with self._lock:
        self._pending_jobs.append({
            "app": app, "job_id": job_id, "ip": client_ip,
            "submitted_at": time.time(), "date": time.strftime("%Y-%m-%d")
        })

def _job_poll_loop(self):
    while True:
        time.sleep(15)
        with self._lock:
            jobs = list(self._pending_jobs)
        if not jobs:
            continue
        done_ids = []
        for job in jobs:
            try:
                port = APPS[job["app"]]["port"]
                conn = http.client.HTTPConnection("127.0.0.1", port, timeout=10)
                conn.request("GET", f"/api/jobs/{job['job_id']}")
                resp = conn.getresponse()
                if resp.status == 200:
                    data = json.loads(resp.read())
                    status = data.get("status", "")
                    terminal = status in ("succeeded", "failed", "completed")
                    if terminal:
                        # Count actual completed sub-tasks, not requested total
                        actual = max(1, int(data.get("done") or 0))
                        self._add_ip_jobs(job["date"], job["ip"], job["app"], actual)
                        done_ids.append(job["job_id"])
                conn.close()
            except Exception:
                pass
            if time.time() - job["submitted_at"] > 7200:
                done_ids.append(job["job_id"])
        if done_ids:
            with self._lock:
                self._pending_jobs = [j for j in self._pending_jobs if j["job_id"] not in done_ids]

def _is_job_request(self, method: str, path: str) -> bool:
    if method != "POST":
        return False
    job_patterns = ["/api/jobs", "/api/text2image", "/api/image2image", "/api/text2video",
                    "/api/image2video", "/api/frames2video", "/api/multimodal2video", "/api/multiframe2video"]
    return any(path.startswith(p) for p in job_patterns)

def handle_one_request(self):
    try:
        super().handle_one_request()
    except (BrokenPipeError, ConnectionResetError):
        pass
    except ssl.SSLError as e:
        print(f"  [SSL ERROR] {e}")
    except OSError as e:
        print(f"  [OS ERROR] {e}")

def do_GET(self):
    path = urllib.parse.urlparse(self.path).path

    if path == "/api/platform/status":
        self._platform_status()
    elif path == "/api/platform/stats":
        self._platform_stats()
    elif path == "/api/platform/activity":
        self._platform_activity()
    elif self._try_proxy(path, "GET"):
        pass
    else:
        self._serve_portal(path)

def do_POST(self):
    path = urllib.parse.urlparse(self.path).path
    if not self._try_proxy(path, "POST"):
        self._json(404, {"ok": False, "error": "not found"})

def _platform_status(self):
    lan_ip = get_lan_ip()
    apps_info = []
    for name, config in APPS.items():
        info = {"name": name, "port": config["port"], **manager.status.get(name, {"status": "unknown"})}
        info["url"] = f"/{name}/"
        apps_info.append(info)
    self._json(200, {"ok": True, "lan_ip": lan_ip, "portal_port": PORTAL_PORT, "apps": apps_info})

def _platform_activity(self):
    merged = []
    for name, config in APPS.items():
        try:
            conn = http.client.HTTPConnection("127.0.0.1", config["port"], timeout=5)
            conn.request("GET", "/api/activity")
            resp = conn.getresponse()
            if resp.status == 200:
                data = json.loads(resp.read())
                items = data.get("items") or data.get("history") or []
                for item in items[:20]:
                    item["_app"] = name
                    merged.append(item)
            conn.close()
        except Exception:
            pass
    merged.sort(key=lambda x: x.get("created_at") or x.get("time") or "", reverse=True)
    self._json(200, {"ok": True, "activity": merged[:50]})

def _try_proxy(self, path: str, method: str) -> bool:
    for app_name, config in APPS.items():
        prefix = f"/{app_name}"
        if path == prefix or path.startswith(prefix + "/"):
            target_path = path[len(prefix):] or "/"
            self._proxy(app_name, config["port"], method, target_path)
            return True
    return False

def _proxy(self, app_name: str, port: int, method: str, target_path: str):
    # NEVER trust client-provided X-Forwarded-For — use real TCP address.
    # Portal is the edge; sub-apps trust X-Forwarded-For from Portal only.
    client_ip = self.client_address[0]
    is_job = tracker._is_job_request(method, target_path)
    tracker.record(app_name, client_ip, method, target_path)

    try:
        body = None
        if method == "POST":
            length = int(self.headers.get("Content-Length") or "0")
            if length > 0:
                body = self.rfile.read(length)

        conn = http.client.HTTPConnection("127.0.0.1", port, timeout=300)
        headers = {}
        for key in ("Content-Type", "Content-Length", "Accept", "Accept-Encoding", "X-Workspace-Id"):
            val = self.headers.get(key)
            if val:
                headers[key] = val
        headers["X-Forwarded-For"] = client_ip

        conn.request(method, target_path, body=body, headers=headers)
        resp = conn.getresponse()

        resp_body = resp.read()

        if is_job and resp.status in (200, 201):
            try:
                resp_data = json.loads(resp_body)
                job_id = resp_data.get("job_id") or resp_data.get("id")
                if job_id:
                    tracker.register_job(app_name, str(job_id), client_ip)
            except Exception:
                pass

        self.send_response(resp.status)
        for key, value in resp.getheaders():
            if key.lower() in ("transfer-encoding", "connection", "server", "date", "content-length"):
                continue
            self.send_header(key, value)
        self._cors_headers()
        self.send_header("Content-Length", str(len(resp_body)))
        self.end_headers()
        self.wfile.write(resp_body)
        conn.close()
    except (BrokenPipeError, ConnectionResetError, ssl.SSLError):
        # Client disconnected — nothing to do
        pass
    except Exception as exc:
        # Truncate to avoid leaking backend response bodies (may contain API keys)
        msg = str(exc)
        if len(msg) > 300:
            msg = msg[:300] + "..."
        try:
            self._json(502, {"ok": False, "error": f"proxy error: {msg}"})
        except (BrokenPipeError, ConnectionResetError, ssl.SSLError, OSError):
            pass

    def shutdown_handler(sig, frame):
        raise KeyboardInterrupt

    signal.signal(signal.SIGINT, shutdown_handler)
    if hasattr(signal, "SIGTERM"):
        signal.signal(signal.SIGTERM, shutdown_handler)
    # Windows: SIGBREAK is the closest equivalent to SIGTERM
    elif hasattr(signal, "SIGBREAK"):
        signal.signal(signal.SIGBREAK, shutdown_handler)

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        pass
    finally:
        manager.shutdown()
        if redirect_server:
            redirect_server.shutdown()
        server.server_close()


if __name__ == "__main__":
    main()

:root {
  color-scheme: light;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  background: #f6f7f9;
  color: #17191f;
}
* { box-sizing: border-box; margin: 0; padding: 0; }
body { min-height: 100vh; }

/* === Portal Bar === */
.portal-bar {
  position: sticky; top: 0; z-index: 100;
  display: flex; align-items: center; justify-content: space-between;
  padding: 10px 20px;
  background: #ffffff; border-bottom: 1px solid #dde1e8;
}
.portal-bar-left { display: flex; align-items: center; gap: 14px; }
.portal-title { font-size: 16px; font-weight: 760; }
.portal-lan { background: #e0f2fe; color: #0369a1; padding: 4px 10px; border-radius: 6px; font-size: 12px; font-weight: 600; }
.portal-bar-stats { font-size: 12px; color: #697386; font-weight: 600; }

/* === App Tabs === */
.app-tabs-bar {
  position: sticky; top: 47px; z-index: 99;
  display: flex; gap: 0;
  background: #ffffff; border-bottom: 1px solid #dde1e8;
  padding: 0 20px;
}
.app-tab {
  padding: 10px 20px; border: none; background: none;
  font-size: 13px; font-weight: 650; color: #4b5565; cursor: pointer;
  border-bottom: 2px solid transparent; transition: all .15s;
}
.app-tab:hover { color: #17191f; }
.app-tab.active { color: #2673e8; border-bottom-color: #2673e8; }

/* === Tab Panels === */
.tab-panel { display: none; }
.tab-panel.active { display: block; }

/* === App Layout === */
.app { display: grid; grid-template-columns: 340px minmax(0, 1fr); min-height: calc(100vh - 94px); }
.sidebar { background: #ffffff; border-right: 1px solid #dde1e8; padding: 16px; overflow: auto; max-height: calc(100vh - 94px); position: sticky; top: 94px; }
.workspace { display: grid; grid-template-rows: auto auto minmax(260px, 1fr); gap: 14px; padding: 16px; overflow: auto; }
.panel { background: #ffffff; border: 1px solid #dde1e8; border-radius: 8px; padding: 14px; }

/* === Typography === */
h1 { margin: 0 0 14px; font-size: 22px; font-weight: 760; display: flex; align-items: center; gap: 10px; }
h2 { margin: 0 0 10px; font-size: 14px; font-weight: 720; }
section { margin-bottom: 16px; }
label { display: grid; gap: 4px; margin-bottom: 10px; font-size: 12px; font-weight: 650; color: #4b5565; }
.hint { margin: -2px 0 8px; color: #697386; font-size: 11px; }

/* === Form Controls === */
input, select, textarea {
  width: 100%; border: 1px solid #cbd2dd; border-radius: 7px;
  background: #ffffff; color: #17191f; font: inherit; font-size: 13px; padding: 8px 10px; outline: none;
}
input:focus, select:focus, textarea:focus { border-color: #2673e8; box-shadow: 0 0 0 3px rgba(38,115,232,0.12); }
textarea { min-height: 160px; resize: vertical; line-height: 1.5; }
.grid2 { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; }
.toggles { display: grid; grid-template-columns: 1fr 1fr; gap: 4px 10px; margin-bottom: 10px; }
.toggles label { display: flex; align-items: center; gap: 6px; margin: 0; }
.toggles input { width: 15px; height: 15px; }

/* === Buttons === */
button { width: 100%; height: 38px; border: 0; border-radius: 7px; background: #17191f; color: #ffffff; font-weight: 720; font-size: 13px; cursor: pointer; }
button:disabled { opacity: 0.55; cursor: wait; }
.rowButtons { display: grid; grid-template-columns: repeat(3, 1fr); gap: 6px; margin: -2px 0 10px; }
.rowButtons.outputDirBtns { grid-template-columns: repeat(5, 1fr); }
.rowButtons button { height: 30px; border: 1px solid #cbd2dd; background: #ffffff; color: #293244; font-size: 11px; }
.archiveBox { margin-top: 14px; padding-top: 14px; border-top: 1px solid #dde1e8; }
.archiveActions { grid-template-columns: 1fr 1fr 1fr; }
.btn-small { width: auto; height: 30px; padding: 0 10px; border: 1px solid #cbd2dd; background: #fff; color: #293244; font-size: 11px; border-radius: 6px; }
.btn-icon { width: 28px; height: 28px; border: 1px solid #cbd2dd; background: #fff; color: #293244; font-size: 16px; border-radius: 6px; }

/* === Upload === */
.uploadGrid { display: grid; gap: 8px; margin-bottom: 12px; }
.uploadGrid.two { grid-template-columns: repeat(2, 1fr); }
.uploadGrid.three, .uploadGrid.refs { grid-template-columns: repeat(3, 1fr); }
.drop { min-height: 72px; margin: 0; padding: 10px; border: 1px dashed #aeb8c7; border-radius: 8px; background: #f8fafc; color: #344054; align-content: center; text-align: center; cursor: pointer; font-size: 12px; position: relative; }
.drop.hasPreview { min-height: 110px; padding: 6px; }
.drop.isDragging { border-color: #2673e8; background: #eef5ff; }
.drop input { display: none; }
.drop span { display: block; margin-top: 4px; color: #697386; font-size: 11px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.removeMediaBtn { position: absolute; top: 4px; right: 4px; width: auto; height: 22px; padding: 0 6px; border: 1px solid #d0d5dd; border-radius: 4px; background: rgba(255,255,255,0.9); color: #ef4444; font-size: 10px; cursor: pointer; display: none; z-index: 2; }
.drop.hasPreview .removeMediaBtn { display: block; }
.preview { display: block; width: 100%; height: 72px; object-fit: contain; border-radius: 5px; margin-top: 4px; background: #e8edf4; cursor: zoom-in; }
audio.preview { height: 32px; cursor: default; }

/* === Preview Dialog === */
.previewDialog { width: min(92vw, 1000px); max-height: 92vh; border: 0; border-radius: 8px; padding: 16px; background: #fff; box-shadow: 0 24px 80px rgba(15,23,42,0.28); }
.previewDialog::backdrop { background: rgba(15,23,42,0.64); }
#closePreviewBtn { position: absolute; top: 8px; right: 8px; width: 30px; height: 30px; border: 1px solid #cbd2dd; border-radius: 50%; background: #fff; color: #17191f; font-size: 20px; line-height: 1; }
#previewDialogBody { display: grid; place-items: center; min-height: 200px; }
#previewDialogBody img, #previewDialogBody video { max-width: 100%; max-height: 82vh; object-fit: contain; border-radius: 6px; }

/* === Results === */
.resultHeader { display: flex; align-items: center; justify-content: space-between; margin-bottom: 10px; }
.results { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 10px; margin-bottom: 10px; }
.result { border: 1px solid #dde1e8; border-radius: 8px; padding: 10px; background: #fbfcfe; }
.result video, .result img { width: 100%; border-radius: 5px; }
.result video { aspect-ratio: 16/9; background: #111; }
.result a { display: inline-block; margin-top: 6px; color: #155eef; font-size: 12px; font-weight: 700; text-decoration: none; }
.meta { margin-top: 6px; color: #4b5565; font-size: 11px; overflow-wrap: anywhere; }
pre { min-height: 80px; max-height: 200px; overflow: auto; margin: 0; padding: 10px; border-radius: 7px; background: #101828; color: #d1e0ff; font-size: 11px; line-height: 1.4; }

/* === Status dots === */
.app-status-dot { display: inline-block; width: 9px; height: 9px; border-radius: 50%; background: #9ca3af; vertical-align: middle; }
.app-status-dot.ready { background: #10b981; }
.app-status-dot.starting { background: #f59e0b; }
.app-status-dot.crashed, .app-status-dot.down { background: #ef4444; }

/* === Stats Panel === */
.portal-content { max-width: 1000px; margin: 0 auto; padding: 24px; }
.stats-panel, .activity-panel { background: #fff; border: 1px solid #dde1e8; border-radius: 12px; padding: 20px; margin-bottom: 20px; }
.stats-panel h2, .activity-panel h2 { font-size: 15px; font-weight: 720; margin-bottom: 14px; }
.stats-row { display: grid; grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); gap: 10px; margin-bottom: 14px; }
.stat-card { background: #f8fafc; border: 1px solid #e8edf4; border-radius: 8px; padding: 14px; text-align: center; }
.stat-value { font-size: 24px; font-weight: 760; color: #2673e8; }
.stat-label { font-size: 11px; color: #697386; margin-top: 3px; }
.stats-by-app { display: grid; grid-template-columns: repeat(auto-fill, minmax(180px, 1fr)); gap: 8px; }
.app-stat-item { display: flex; justify-content: space-between; padding: 8px 12px; background: #f8fafc; border-radius: 6px; font-size: 12px; }
.app-stat-item .name { font-weight: 600; }
.app-stat-item .count { color: #2673e8; font-weight: 700; }
.activity-list { max-height: 300px; overflow-y: auto; }
.activity-item { display: grid; grid-template-columns: 70px 90px 1fr; gap: 10px; padding: 6px 0; border-bottom: 1px solid #f1f3f7; font-size: 11px; align-items: center; }
.activity-time { color: #697386; }
.activity-app { font-weight: 600; padding: 2px 6px; background: #f1f3f7; border-radius: 4px; text-align: center; }
.activity-detail { color: #293244; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }

/* IP Stats Table */
.ip-stats-table { width: 100%; border-collapse: collapse; font-size: 13px; }
.ip-stats-table th { text-align: left; padding: 8px 12px; background: #f8fafc; border-bottom: 2px solid #dde1e8; font-weight: 700; color: #4b5565; font-size: 12px; }
.ip-stats-table td { padding: 8px 12px; border-bottom: 1px solid #f1f3f7; }
.ip-stats-table tr:hover td { background: #f8fafc; }
.ip-stats-table td:last-child { font-weight: 700; color: #2673e8; }

/* === Dreamina specific === */
.setup-view { display: flex; align-items: center; justify-content: center; min-height: 400px; }
.setup-card { text-align: center; max-width: 420px; padding: 32px; }
.setup-card h2 { margin-bottom: 12px; }
.setup-log { text-align: left; max-height: 200px; overflow: auto; margin-top: 12px; }
.spinner { width: 24px; height: 24px; border: 3px solid #dde1e8; border-top-color: #2673e8; border-radius: 50%; animation: spin .8s linear infinite; margin: 12px auto; }
@keyframes spin { to { transform: rotate(360deg); } }
.hidden { display: none !important; }
.status-badge { font-size: 11px; padding: 3px 8px; border-radius: 4px; background: #f1f3f7; }
.status-badge.ok { background: #d1fae5; color: #065f46; }
.status-badge.error { background: #fee2e2; color: #991b1b; }
.credit { font-size: 11px; color: #697386; margin-left: 8px; }
.sidebar-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 10px; }
.major-tabs, .tabs { display: flex; gap: 6px; }
.tabBtn { width: auto; min-width: 60px; height: 30px; padding: 0 10px; border: 1px solid #cbd2dd; background: #fff; color: #293244; font-size: 12px; }
.tabBtn.isActive { border-color: #17191f; background: #17191f; color: #fff; }
.sub-tabs { display: flex; gap: 4px; margin-bottom: 10px; }
.sub-tab { width: auto; height: 28px; padding: 0 8px; border: 1px solid #cbd2dd; background: #fff; color: #293244; font-size: 11px; border-radius: 5px; }
.sub-tab.active, .sub-tab.isActive { border-color: #2673e8; background: #eef5ff; color: #2673e8; }
.jobs-list, .history-list { min-height: 120px; }
.filter-bar { display: flex; gap: 4px; }
.filter-btn { width: auto; height: 26px; padding: 0 8px; border: 1px solid #cbd2dd; background: #fff; color: #293244; font-size: 11px; border-radius: 5px; }
.filter-btn.active { border-color: #2673e8; color: #2673e8; }
.running-count { font-size: 12px; color: #697386; }

/* === Accounts Section === */
.accounts-section { margin-bottom: 14px; padding-bottom: 14px; border-bottom: 1px solid #dde1e8; }
.accounts-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 8px; }
.dispatch-select { width: auto; padding: 4px 8px; font-size: 11px; border-radius: 5px; }
.accounts-list { display: flex; flex-direction: column; gap: 4px; }
.account-item { display: grid; grid-template-columns: 1fr auto; gap: 6px; align-items: center; padding: 6px 8px; border: 1px solid #e8edf4; border-radius: 6px; font-size: 12px; cursor: pointer; }
.account-item.active { border-color: #2673e8; background: #f0f6ff; }
.account-item:hover { background: #f8fafc; }
.account-item.active:hover { background: #f0f6ff; }
.account-info { display: flex; align-items: center; gap: 8px; }
.account-name { font-weight: 600; }
.account-credit { font-size: 11px; color: #2673e8; font-weight: 600; }
.account-status { font-size: 10px; padding: 1px 5px; border-radius: 3px; background: #fee2e2; color: #991b1b; }
.account-status.ok { background: #d1fae5; color: #065f46; }
.account-actions { display: flex; gap: 3px; }
.activity-counts { display: flex; gap: 12px; font-size: 12px; margin-bottom: 10px; color: #4b5565; }
.activity-counts .act-ok { color: #10b981; font-weight: 600; }
.activity-counts .act-fail { color: #ef4444; font-weight: 600; }
.activity-records { max-height: 400px; overflow-y: auto; }
.act-item { display: grid; grid-template-columns: 70px 90px 1fr; gap: 8px; padding: 8px 6px; border-bottom: 1px solid #f1f3f7; font-size: 12px; cursor: pointer; align-items: center; border-radius: 4px; }
.act-item:hover { background: #f8fafc; }
.act-status { font-weight: 600; font-size: 11px; padding: 2px 6px; border-radius: 4px; text-align: center; }
.act-status.succeeded { background: #d1fae5; color: #065f46; }
.act-status.failed { background: #fee2e2; color: #991b1b; }
.act-status.running { background: #e0f2fe; color: #0369a1; }
.act-time { color: #697386; font-size: 11px; }
.act-title { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: #293244; }
.act-detail { padding: 4px 0; }
.act-detail-meta { font-size: 12px; color: #4b5565; margin-bottom: 8px; }
.act-detail pre { background: #101828; color: #d1e0ff; padding: 10px; border-radius: 7px; font-size: 11px; overflow: auto; }

/* === Responsive === */
@media (max-width: 960px) { .app { grid-template-columns: 1fr; } .sidebar { max-height: none; position: static; border-right: 0; border-bottom: 1px solid #dde1e8; } }
@media (max-width: 680px) { .grid2, .rowButtons, .uploadGrid.two, .uploadGrid.three, .uploadGrid.refs, .toggles { grid-template-columns: 1fr; } .app-tabs-bar { overflow-x: auto; } }

