  cursor: pointer;
  transition: all 0.15s;
}
.filter-btn:hover { color: #17191f; }
.filter-btn.active { background: #f1f3f7; color: #17191f; }

/* === Jobs Grid === */
.jobs-list, .history-list {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 12px;
}

.job-card {
  background: #fbfcfe;
  border-radius: 8px;
  padding: 14px;
  border: 1px solid #dde1e8;
  transition: box-shadow 0.15s;
}
.job-card:hover { box-shadow: 0 2px 12px rgba(15, 23, 42, 0.06); }

.job-card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
}

.job-type {
