}
.job-status.pending { background: #fef3c7; color: #92400e; }
.job-status.running { background: #e0f2fe; color: #0369a1; }
.job-status.completed { background: #d1fae5; color: #065f46; }
.job-status.failed { background: #fee2e2; color: #991b1b; }
.job-status.querying { background: #e0f2fe; color: #0369a1; }

.job-prompt {
  font-size: 13px;
  color: #293244;
  margin-bottom: 8px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  line-height: 1.5;
}

.job-time { font-size: 11px; color: #697386; }

.job-error {
  font-size: 12px;
  color: #991b1b;
  margin-top: 8px;
  padding: 8px 10px;
  background: #fef2f2;
  border-radius: 6px;
