}
.result-thumb:hover { transform: scale(1.04); }

.job-actions { margin-top: 8px; }

.btn-retry {
  font-size: 12px;
  padding: 5px 12px;
  border-radius: 6px;
  border: 1px solid #f59e0b;
  background: #fffbeb;
  color: #92400e;
  font-weight: 600;
  cursor: pointer;
}
.btn-retry:hover { background: #fef3c7; }

.btn-template {
  font-size: 12px;
  padding: 5px 12px;
  border-radius: 6px;
  border: 1px solid #2673e8;
  background: #eff6ff;
  color: #1d4ed8;
  font-weight: 600;
  cursor: pointer;
}
