}

.close-btn {
  position: absolute;
  top: 10px;
  right: 10px;
  width: 34px;
  height: 34px;
  border: 1px solid #cbd2dd;
  border-radius: 50%;
  background: #ffffff;
  color: #17191f;
  font-size: 22px;
  line-height: 1;
